    async fn start_reconnecting_v2_multi_connection_session_mutation_server(
        worker_label: &'static str,
    ) -> (String, Arc<Mutex<Vec<String>>>) {
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("listener should bind");
        let addr = listener.local_addr().expect("listener address");
        let received_methods = Arc::new(Mutex::new(Vec::new()));
        let received_methods_for_task = Arc::clone(&received_methods);
        tokio::spawn(async move {
            for connection_index in 0..4 {
                let (stream, _) = listener.accept().await.expect("accept should succeed");
                let mut websocket = tokio_tungstenite::accept_async(stream)
                    .await
                    .expect("websocket upgrade should succeed");

                expect_remote_initialize(&mut websocket).await;
                match connection_index {
                    0 | 2 => {
                        websocket
                            .close(None)
                            .await
                            .expect("close frame should send");
                    }
                    1 => {
                        tokio::spawn(async move {
                            tokio::time::sleep(Duration::from_secs(60)).await;
                            drop(websocket);
                        });
                    }
                    3 => loop {
                        let request = read_websocket_request(&mut websocket).await;
                        received_methods_for_task
                            .lock()
                            .await
                            .push(request.method.clone());

                        let result = match request.method.as_str() {
                            "externalAgentConfig/import" => {
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Notification(
                                        codex_app_server_protocol::JSONRPCNotification {
                                            method: "externalAgentConfig/import/completed"
                                                .to_string(),
                                            params: Some(serde_json::json!({})),
                                        },
                                    ),
                                )
                                .await;
                                serde_json::json!({})
                            }
                            "config/value/write" | "config/batchWrite" => serde_json::json!({
                                "status": "ok",
                                "version": worker_label,
                                "filePath": "/tmp/shared/config.toml",
                                "overriddenMetadata": null,
                            }),
                            "fs/watch" => serde_json::json!({
                                "path": request
                                    .params
                                    .as_ref()
                                    .and_then(|params| params.get("path"))
                                    .cloned()
                                    .expect("fs/watch should include path"),
                            }),
                            "fs/unwatch" => serde_json::json!({}),
                            "memory/reset" | "account/logout" => serde_json::json!({}),
                            method => panic!("unexpected request method: {method}"),
                        };
                        write_websocket_message(
                            &mut websocket,
                            JSONRPCMessage::Response(JSONRPCResponse {
                                id: request.id,
                                result,
                            }),
                        )
                        .await;
                    },
                    _ => unreachable!("unexpected connection index"),
                }
            }
        });
        (format!("ws://{addr}"), received_methods)
    }

    async fn start_reconnecting_v2_multi_connection_state_notification_server() -> String {
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("listener should bind");
        let addr = listener.local_addr().expect("listener address");
        tokio::spawn(async move {
            for connection_index in 0..3 {
                let (stream, _) = listener.accept().await.expect("accept should succeed");
                let mut websocket = tokio_tungstenite::accept_async(stream)
                    .await
                    .expect("websocket upgrade should succeed");

                expect_remote_initialize(&mut websocket).await;
                match connection_index {
                    0 => {
                        websocket
                            .close(None)
                            .await
                            .expect("close frame should send");
                    }
                    1 => {
                        tokio::spawn(async move {
                            tokio::time::sleep(Duration::from_secs(60)).await;
                            drop(websocket);
                        });
                    }
                    2 => {
                        for notification in [
                            serde_json::json!({
                                "method": "account/updated",
                                "params": {
                                    "authMode": null,
                                    "planType": null,
                                },
                            }),
                            serde_json::json!({
                                "method": "account/rateLimits/updated",
                                "params": {
                                    "rateLimits": {
                                        "limitId": null,
                                        "limitName": null,
                                        "primary": null,
                                        "secondary": null,
                                        "credits": null,
                                        "planType": null,
                                        "rateLimitReachedType": null,
                                    },
                                },
                            }),
                            serde_json::json!({
                                "method": "app/list/updated",
                                "params": {
                                    "data": [{
                                        "id": "calendar",
                                        "name": "calendar",
                                        "description": null,
                                        "logoUrl": null,
                                        "logoUrlDark": null,
                                        "distributionChannel": null,
                                        "branding": null,
                                        "appMetadata": null,
                                        "labels": null,
                                        "installUrl": null,
                                    }],
                                },
                            }),
                            serde_json::json!({
                                "method": "account/login/completed",
                                "params": {
                                    "loginId": null,
                                    "success": true,
                                    "error": null,
                                },
                            }),
                            serde_json::json!({
                                "method": "mcpServer/oauthLogin/completed",
                                "params": {
                                    "name": "calendar-mcp",
                                    "success": true,
                                    "error": null,
                                },
                            }),
                            serde_json::json!({
                                "method": "mcpServer/startupStatus/updated",
                                "params": {
                                    "name": "calendar-mcp",
                                    "status": "ready",
                                    "error": null,
                                },
                            }),
                            serde_json::json!({
                                "method": "warning",
                                "params": {
                                    "threadId": null,
                                    "message": "shared warning",
                                },
                            }),
                            serde_json::json!({
                                "method": "configWarning",
                                "params": {
                                    "summary": "shared config warning",
                                    "details": "check your shared config",
                                },
                            }),
                            serde_json::json!({
                                "method": "deprecationNotice",
                                "params": {
                                    "summary": "shared deprecation notice",
                                    "details": "update the shared workflow",
                                },
                            }),
                        ] {
                            write_websocket_message(
                                &mut websocket,
                                serde_json::from_value::<JSONRPCMessage>(notification)
                                    .expect("notification should decode"),
                            )
                            .await;
                        }

                        while let Some(frame) = websocket.next().await {
                            match frame.expect("follow-up frame should decode") {
                                Message::Close(_) => break,
                                Message::Ping(payload) => {
                                    websocket
                                        .send(Message::Pong(payload))
                                        .await
                                        .expect("pong should send");
                                }
                                Message::Text(_)
                                | Message::Binary(_)
                                | Message::Pong(_)
                                | Message::Frame(_) => {}
                            }
                        }
                    }
                    _ => unreachable!("unexpected connection index"),
                }
            }
        });
        format!("ws://{addr}")
    }

    async fn start_reconnecting_v2_multi_connection_realtime_server(
        thread_id: &'static str,
        preview: &'static str,
        session_id: &'static str,
        transcript_delta: &'static str,
        transcript_done: &'static str,
    ) -> String {
        start_reconnecting_v2_multi_connection_realtime_server_with_voices(
            thread_id,
            preview,
            session_id,
            transcript_delta,
            transcript_done,
            RealtimeVoicesList::builtin(),
        )
        .await
    }

    async fn start_reconnecting_v2_multi_connection_realtime_server_with_voices(
        thread_id: &'static str,
        preview: &'static str,
        session_id: &'static str,
        transcript_delta: &'static str,
        transcript_done: &'static str,
        realtime_voices: RealtimeVoicesList,
    ) -> String {
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("listener should bind");
        let addr = listener.local_addr().expect("listener address");
        tokio::spawn(async move {
            for connection_index in 0..3 {
                let (stream, _) = listener.accept().await.expect("accept should succeed");
                let realtime_voices = realtime_voices.clone();
                let mut websocket = tokio_tungstenite::accept_async(stream)
                    .await
                    .expect("websocket upgrade should succeed");

                expect_remote_initialize(&mut websocket).await;
                match connection_index {
                    0 => {
                        websocket
                            .close(None)
                            .await
                            .expect("close frame should send");
                    }
                    1 => {
                        tokio::spawn(async move {
                            tokio::time::sleep(Duration::from_secs(60)).await;
                            drop(websocket);
                        });
                    }
                    2 => loop {
                        let request = read_websocket_request(&mut websocket).await;
                        match request.method.as_str() {
                            "thread/realtime/listVoices" => {
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({
                                            "voices": serde_json::to_value(&realtime_voices)
                                                .expect("realtime voices should serialize"),
                                        }),
                                    }),
                                )
                                .await;
                            }
                            "thread/start" => {
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({
                                            "thread": mock_thread(thread_id, preview),
                                            "model": "gpt-5",
                                            "modelProvider": "openai",
                                            "serviceTier": null,
                                            "cwd": preview,
                                            "instructionSources": [],
                                            "approvalPolicy": "never",
                                            "approvalsReviewer": "user",
                                            "sandbox": {
                                                "type": "dangerFullAccess"
                                            },
                                            "reasoningEffort": null,
                                        }),
                                    }),
                                )
                                .await;
                            }
                            "thread/realtime/start" => {
                                let params = request
                                    .params
                                    .as_ref()
                                    .expect("realtime start params should exist");
                                assert_eq!(params["threadId"], thread_id);
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({}),
                                    }),
                                )
                                .await;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Notification(
                                        codex_app_server_protocol::JSONRPCNotification {
                                            method: "thread/realtime/started".to_string(),
                                            params: Some(serde_json::json!({
                                                "threadId": thread_id,
                                                "sessionId": session_id,
                                                "version": "v2",
                                            })),
                                        },
                                    ),
                                )
                                .await;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Notification(
                                        codex_app_server_protocol::JSONRPCNotification {
                                            method: "thread/realtime/itemAdded".to_string(),
                                            params: Some(serde_json::json!({
                                                "threadId": thread_id,
                                                "item": {
                                                    "type": "message",
                                                    "id": format!("item-{thread_id}"),
                                                },
                                            })),
                                        },
                                    ),
                                )
                                .await;
                            }
                            "thread/realtime/appendText" => {
                                let params = request
                                    .params
                                    .as_ref()
                                    .expect("realtime appendText params should exist");
                                assert_eq!(params["threadId"], thread_id);
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({}),
                                    }),
                                )
                                .await;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Notification(
                                        codex_app_server_protocol::JSONRPCNotification {
                                            method: "thread/realtime/transcript/delta".to_string(),
                                            params: Some(serde_json::json!({
                                                "threadId": thread_id,
                                                "role": "assistant",
                                                "delta": transcript_delta,
                                            })),
                                        },
                                    ),
                                )
                                .await;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Notification(
                                        codex_app_server_protocol::JSONRPCNotification {
                                            method: "thread/realtime/transcript/done".to_string(),
                                            params: Some(serde_json::json!({
                                                "threadId": thread_id,
                                                "role": "assistant",
                                                "text": transcript_done,
                                            })),
                                        },
                                    ),
                                )
                                .await;
                            }
                            "thread/realtime/appendAudio" => {
                                let params = request
                                    .params
                                    .as_ref()
                                    .expect("realtime appendAudio params should exist");
                                assert_eq!(params["threadId"], thread_id);
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({}),
                                    }),
                                )
                                .await;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Notification(
                                        codex_app_server_protocol::JSONRPCNotification {
                                            method: "thread/realtime/outputAudio/delta".to_string(),
                                            params: Some(serde_json::json!({
                                                "threadId": thread_id,
                                                "audio": {
                                                    "data": params["audio"]["data"].clone(),
                                                    "sampleRate": 24000,
                                                    "numChannels": 1,
                                                    "samplesPerChannel": 3,
                                                    "itemId": params["audio"]["itemId"].clone(),
                                                },
                                            })),
                                        },
                                    ),
                                )
                                .await;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Notification(
                                        codex_app_server_protocol::JSONRPCNotification {
                                            method: "thread/realtime/sdp".to_string(),
                                            params: Some(serde_json::json!({
                                                "threadId": thread_id,
                                                "sdp": "v=0\r\no=- 1 2 IN IP4 127.0.0.1\r\ns=Codex\r\n",
                                            })),
                                        },
                                    ),
                                )
                                .await;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Notification(
                                        codex_app_server_protocol::JSONRPCNotification {
                                            method: "thread/realtime/error".to_string(),
                                            params: Some(serde_json::json!({
                                                "threadId": thread_id,
                                                "message": "realtime transport warning",
                                            })),
                                        },
                                    ),
                                )
                                .await;
                            }
                            "thread/realtime/stop" => {
                                let params = request
                                    .params
                                    .as_ref()
                                    .expect("realtime stop params should exist");
                                assert_eq!(params["threadId"], thread_id);
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({}),
                                    }),
                                )
                                .await;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Notification(
                                        codex_app_server_protocol::JSONRPCNotification {
                                            method: "thread/realtime/closed".to_string(),
                                            params: Some(serde_json::json!({
                                                "threadId": thread_id,
                                                "reason": "client requested stop",
                                            })),
                                        },
                                    ),
                                )
                                .await;
                            }
                            method => panic!("unexpected request method: {method}"),
                        }
                    },
                    _ => unreachable!("unexpected connection index"),
                }
            }
        });
        format!("ws://{addr}")
    }

