    async fn start_mock_remote_multi_plugin_server(
        marketplace_name: &'static str,
        preview: &'static str,
        plugin_name: &'static str,
        description: &'static str,
    ) -> String {
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("listener should bind");
        let addr = listener.local_addr().expect("listener address");
        let plugin_id = format!("{plugin_name}@{marketplace_name}");
        let marketplace_path = format!("{preview}/marketplace.json");
        let plugin_path = format!("{preview}/plugins/{plugin_name}");
        tokio::spawn(async move {
            loop {
                let (stream, _) = listener.accept().await.expect("accept should succeed");
                let plugin_id = plugin_id.clone();
                let marketplace_path = marketplace_path.clone();
                let plugin_path = plugin_path.clone();
                tokio::spawn(async move {
                    let mut websocket = tokio_tungstenite::accept_async(stream)
                        .await
                        .expect("websocket upgrade should succeed");
                    expect_remote_initialize(&mut websocket).await;

                    let mut plugin_installed = false;

                    loop {
                        let request = read_websocket_request(&mut websocket).await;
                        match request.method.as_str() {
                            "plugin/list" => {
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({
                                            "marketplaces": [{
                                                "name": marketplace_name,
                                                "path": marketplace_path.clone(),
                                                "interface": {
                                                    "displayName": marketplace_name,
                                                },
                                                "plugins": [{
                                                    "id": plugin_id.clone(),
                                                    "name": plugin_name,
                                                    "source": {
                                                        "type": "local",
                                                        "path": plugin_path.clone(),
                                                    },
                                                    "installed": plugin_installed,
                                                    "enabled": plugin_installed,
                                                    "installPolicy": "AVAILABLE",
                                                    "authPolicy": "ON_INSTALL",
                                                    "interface": {
                                                        "displayName": plugin_name,
                                                        "shortDescription": format!("{plugin_name} short description"),
                                                        "longDescription": null,
                                                        "developerName": null,
                                                        "category": "tools",
                                                        "capabilities": ["commands"],
                                                        "websiteUrl": null,
                                                        "privacyPolicyUrl": null,
                                                        "termsOfServiceUrl": null,
                                                        "defaultPrompt": null,
                                                        "brandColor": null,
                                                        "composerIcon": null,
                                                        "composerIconUrl": null,
                                                        "logo": null,
                                                        "logoUrl": null,
                                                        "screenshots": [],
                                                        "screenshotUrls": [],
                                                    },
                                                }],
                                            }],
                                            "marketplaceLoadErrors": [],
                                            "featuredPluginIds": [plugin_id.clone()],
                                        }),
                                    }),
                                )
                                .await;
                            }
                            "plugin/read" => {
                                let plugin_read_params: PluginReadParams = serde_json::from_value(
                                    request
                                        .params
                                        .clone()
                                        .expect("plugin/read params should exist"),
                                )
                                .expect("plugin/read params should decode");
                                if plugin_read_params.plugin_name != plugin_name
                                    || plugin_read_params.marketplace_path.as_ref().is_none_or(
                                        |path| {
                                            path.as_path()
                                                != std::path::Path::new(&marketplace_path)
                                        },
                                    )
                                {
                                    write_websocket_message(
                                        &mut websocket,
                                        JSONRPCMessage::Error(JSONRPCError {
                                            id: request.id,
                                            error: JSONRPCErrorError {
                                                code: -32602,
                                                message: "plugin not found on worker".to_string(),
                                                data: None,
                                            },
                                        }),
                                    )
                                    .await;
                                    continue;
                                }
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({
                                            "plugin": {
                                                "marketplaceName": marketplace_name,
                                                "marketplacePath": marketplace_path.clone(),
                                                "summary": {
                                                    "id": plugin_id.clone(),
                                                    "name": plugin_name,
                                                    "source": {
                                                        "type": "local",
                                                        "path": plugin_path.clone(),
                                                    },
                                                    "installed": plugin_installed,
                                                    "enabled": plugin_installed,
                                                    "installPolicy": "AVAILABLE",
                                                    "authPolicy": "ON_INSTALL",
                                                    "interface": {
                                                        "displayName": plugin_name,
                                                        "shortDescription": format!("{plugin_name} short description"),
                                                        "longDescription": null,
                                                        "developerName": null,
                                                        "category": "tools",
                                                        "capabilities": ["commands"],
                                                        "websiteUrl": null,
                                                        "privacyPolicyUrl": null,
                                                        "termsOfServiceUrl": null,
                                                        "defaultPrompt": null,
                                                        "brandColor": null,
                                                        "composerIcon": null,
                                                        "composerIconUrl": null,
                                                        "logo": null,
                                                        "logoUrl": null,
                                                        "screenshots": [],
                                                        "screenshotUrls": [],
                                                    },
                                                },
                                                "description": description,
                                                "skills": [],
                                                "apps": [],
                                                "mcpServers": [],
                                            },
                                        }),
                                    }),
                                )
                                .await;
                            }
                            "plugin/install" => {
                                let plugin_install_params: PluginInstallParams =
                                    serde_json::from_value(
                                        request
                                            .params
                                            .clone()
                                            .expect("plugin/install params should exist"),
                                    )
                                    .expect("plugin/install params should decode");
                                if plugin_install_params.plugin_name != plugin_name
                                    || plugin_install_params.marketplace_path.as_ref().is_none_or(
                                        |path| {
                                            path.as_path()
                                                != std::path::Path::new(&marketplace_path)
                                        },
                                    )
                                {
                                    write_websocket_message(
                                        &mut websocket,
                                        JSONRPCMessage::Error(JSONRPCError {
                                            id: request.id,
                                            error: JSONRPCErrorError {
                                                code: -32602,
                                                message: "plugin not found on worker".to_string(),
                                                data: None,
                                            },
                                        }),
                                    )
                                    .await;
                                    continue;
                                }
                                plugin_installed = true;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({
                                            "authPolicy": "ON_INSTALL",
                                            "appsNeedingAuth": [],
                                        }),
                                    }),
                                )
                                .await;
                            }
                            "plugin/uninstall" => {
                                let plugin_uninstall_params: PluginUninstallParams =
                                    serde_json::from_value(
                                        request
                                            .params
                                            .clone()
                                            .expect("plugin/uninstall params should exist"),
                                    )
                                    .expect("plugin/uninstall params should decode");
                                if plugin_uninstall_params.plugin_id != plugin_id {
                                    write_websocket_message(
                                        &mut websocket,
                                        JSONRPCMessage::Error(JSONRPCError {
                                            id: request.id,
                                            error: JSONRPCErrorError {
                                                code: -32602,
                                                message: "plugin not found on worker".to_string(),
                                                data: None,
                                            },
                                        }),
                                    )
                                    .await;
                                    continue;
                                }
                                plugin_installed = false;
                                write_websocket_message(
                                    &mut websocket,
                                    JSONRPCMessage::Response(JSONRPCResponse {
                                        id: request.id,
                                        result: serde_json::json!({}),
                                    }),
                                )
                                .await;
                            }
                            _ => panic!("unexpected request method: {}", request.method),
                        }
                    }
                });
            }
        });
        format!("ws://{addr}")
    }

    async fn start_reconnecting_v2_multi_connection_plugin_server(
        marketplace_name: &'static str,
        preview: &'static str,
        plugin_name: &'static str,
        description: &'static str,
    ) -> String {
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("listener should bind");
        let addr = listener.local_addr().expect("listener address");
        let plugin_id = format!("{plugin_name}@{marketplace_name}");
        let marketplace_path = format!("{preview}/marketplace.json");
        let plugin_path = format!("{preview}/plugins/{plugin_name}");
        tokio::spawn(async move {
            for connection_index in 0..4 {
                let (stream, _) = listener.accept().await.expect("accept should succeed");
                let plugin_id = plugin_id.clone();
                let marketplace_path = marketplace_path.clone();
                let plugin_path = plugin_path.clone();
                let mut websocket = tokio_tungstenite::accept_async(stream)
                    .await
                    .expect("websocket upgrade should succeed");

                expect_remote_initialize(&mut websocket).await;
                match connection_index {
                    0 | 2 => {
                        websocket
                            .close(None)
                            .await
                            .expect("close frame should send");
                    }
                    1 => {
                        tokio::spawn(async move {
                            tokio::time::sleep(Duration::from_secs(60)).await;
                            drop(websocket);
                        });
                    }
                    3 => {
                        let mut plugin_installed = false;
                        loop {
                            let request = read_websocket_request(&mut websocket).await;
                            match request.method.as_str() {
                                "plugin/list" => {
                                    write_websocket_message(
                                        &mut websocket,
                                        JSONRPCMessage::Response(JSONRPCResponse {
                                            id: request.id,
                                            result: serde_json::json!({
                                                "marketplaces": [{
                                                    "name": marketplace_name,
                                                    "path": marketplace_path.clone(),
                                                    "interface": {
                                                        "displayName": marketplace_name,
                                                    },
                                                    "plugins": [{
                                                        "id": plugin_id.clone(),
                                                        "name": plugin_name,
                                                        "source": {
                                                            "type": "local",
                                                            "path": plugin_path.clone(),
                                                        },
                                                        "installed": plugin_installed,
                                                        "enabled": plugin_installed,
                                                        "installPolicy": "AVAILABLE",
                                                        "authPolicy": "ON_INSTALL",
                                                        "interface": {
                                                            "displayName": plugin_name,
                                                            "shortDescription": format!("{plugin_name} short description"),
                                                            "longDescription": null,
                                                            "developerName": null,
                                                            "category": "tools",
                                                            "capabilities": ["commands"],
                                                            "websiteUrl": null,
                                                            "privacyPolicyUrl": null,
                                                            "termsOfServiceUrl": null,
                                                            "defaultPrompt": null,
                                                            "brandColor": null,
                                                            "composerIcon": null,
                                                            "composerIconUrl": null,
                                                            "logo": null,
                                                            "logoUrl": null,
                                                            "screenshots": [],
                                                            "screenshotUrls": [],
                                                        },
                                                    }],
                                                }],
                                                "marketplaceLoadErrors": [],
                                                "featuredPluginIds": [plugin_id.clone()],
                                            }),
                                        }),
                                    )
                                    .await;
                                }
                                "plugin/read" => {
                                    let plugin_read_params: PluginReadParams =
                                        serde_json::from_value(
                                            request
                                                .params
                                                .clone()
                                                .expect("plugin/read params should exist"),
                                        )
                                        .expect("plugin/read params should decode");
                                    if plugin_read_params.plugin_name != plugin_name
                                        || plugin_read_params.marketplace_path.as_ref().is_none_or(
                                            |path| {
                                                path.as_path()
                                                    != std::path::Path::new(&marketplace_path)
                                            },
                                        )
                                    {
                                        write_websocket_message(
                                            &mut websocket,
                                            JSONRPCMessage::Error(JSONRPCError {
                                                id: request.id,
                                                error: JSONRPCErrorError {
                                                    code: -32602,
                                                    message: "plugin not found on worker"
                                                        .to_string(),
                                                    data: None,
                                                },
                                            }),
                                        )
                                        .await;
                                        continue;
                                    }
                                    write_websocket_message(
                                        &mut websocket,
                                        JSONRPCMessage::Response(JSONRPCResponse {
                                            id: request.id,
                                            result: serde_json::json!({
                                                "plugin": {
                                                    "marketplaceName": marketplace_name,
                                                    "marketplacePath": marketplace_path.clone(),
                                                    "summary": {
                                                        "id": plugin_id.clone(),
                                                        "name": plugin_name,
                                                        "source": {
                                                            "type": "local",
                                                            "path": plugin_path.clone(),
                                                        },
                                                        "installed": plugin_installed,
                                                        "enabled": plugin_installed,
                                                        "installPolicy": "AVAILABLE",
                                                        "authPolicy": "ON_INSTALL",
                                                        "interface": {
                                                            "displayName": plugin_name,
                                                            "shortDescription": format!("{plugin_name} short description"),
                                                            "longDescription": null,
                                                            "developerName": null,
                                                            "category": "tools",
                                                            "capabilities": ["commands"],
                                                            "websiteUrl": null,
                                                            "privacyPolicyUrl": null,
                                                            "termsOfServiceUrl": null,
                                                            "defaultPrompt": null,
                                                            "brandColor": null,
                                                            "composerIcon": null,
                                                            "composerIconUrl": null,
                                                            "logo": null,
                                                            "logoUrl": null,
                                                            "screenshots": [],
                                                            "screenshotUrls": [],
                                                        },
                                                    },
                                                    "description": description,
                                                    "skills": [],
                                                    "apps": [],
                                                    "mcpServers": [],
                                                },
                                            }),
                                        }),
                                    )
                                    .await;
                                }
                                "plugin/install" => {
                                    let plugin_install_params: PluginInstallParams =
                                        serde_json::from_value(
                                            request
                                                .params
                                                .clone()
                                                .expect("plugin/install params should exist"),
                                        )
                                        .expect("plugin/install params should decode");
                                    if plugin_install_params.plugin_name != plugin_name
                                        || plugin_install_params
                                            .marketplace_path
                                            .as_ref()
                                            .is_none_or(|path| {
                                                path.as_path()
                                                    != std::path::Path::new(&marketplace_path)
                                            })
                                    {
                                        write_websocket_message(
                                            &mut websocket,
                                            JSONRPCMessage::Error(JSONRPCError {
                                                id: request.id,
                                                error: JSONRPCErrorError {
                                                    code: -32602,
                                                    message: "plugin not found on worker"
                                                        .to_string(),
                                                    data: None,
                                                },
                                            }),
                                        )
                                        .await;
                                        continue;
                                    }
                                    plugin_installed = true;
                                    write_websocket_message(
                                        &mut websocket,
                                        JSONRPCMessage::Response(JSONRPCResponse {
                                            id: request.id,
                                            result: serde_json::json!({
                                                "authPolicy": "ON_INSTALL",
                                                "appsNeedingAuth": [],
                                            }),
                                        }),
                                    )
                                    .await;
                                }
                                "plugin/uninstall" => {
                                    let plugin_uninstall_params: PluginUninstallParams =
                                        serde_json::from_value(
                                            request
                                                .params
                                                .clone()
                                                .expect("plugin/uninstall params should exist"),
                                        )
                                        .expect("plugin/uninstall params should decode");
                                    if plugin_uninstall_params.plugin_id != plugin_id {
                                        write_websocket_message(
                                            &mut websocket,
                                            JSONRPCMessage::Error(JSONRPCError {
                                                id: request.id,
                                                error: JSONRPCErrorError {
                                                    code: -32602,
                                                    message: "plugin not found on worker"
                                                        .to_string(),
                                                    data: None,
                                                },
                                            }),
                                        )
                                        .await;
                                        continue;
                                    }
                                    plugin_installed = false;
                                    write_websocket_message(
                                        &mut websocket,
                                        JSONRPCMessage::Response(JSONRPCResponse {
                                            id: request.id,
                                            result: serde_json::json!({}),
                                        }),
                                    )
                                    .await;
                                }
                                method => panic!("unexpected request method: {method}"),
                            }
                        }
                    }
                    _ => unreachable!("unexpected connection index"),
                }
            }
        });
        format!("ws://{addr}")
    }

    async fn drive_mock_remote_multi_connection_server_request_session(
        websocket: &mut tokio_tungstenite::WebSocketStream<tokio::net::TcpStream>,
        thread_id: &str,
        preview: &str,
        expected_answer: &str,
        previous_account_id: &str,
    ) {
        let thread_start_request = read_websocket_request(websocket).await;
        assert_eq!(thread_start_request.method, "thread/start");
        write_websocket_message(
            websocket,
            JSONRPCMessage::Response(JSONRPCResponse {
                id: thread_start_request.id,
                result: serde_json::json!({
                    "thread": mock_thread(thread_id, preview),
                    "model": "gpt-5",
                    "modelProvider": "openai",
                    "serviceTier": null,
                    "cwd": preview,
                    "instructionSources": [],
                    "approvalPolicy": "never",
                    "approvalsReviewer": "user",
                    "sandbox": {
                        "type": "dangerFullAccess"
                    },
                    "reasoningEffort": null,
                }),
            }),
        )
        .await;

        write_websocket_message(
            websocket,
            JSONRPCMessage::Request(codex_app_server_protocol::JSONRPCRequest {
                id: RequestId::String("shared-server-request".to_string()),
                method: "item/tool/requestUserInput".to_string(),
                params: Some(
                    serde_json::to_value(codex_app_server_protocol::ToolRequestUserInputParams {
                        thread_id: thread_id.to_string(),
                        turn_id: "turn-remote-workflow".to_string(),
                        item_id: "tool-call-remote-workflow".to_string(),
                        questions: vec![ToolRequestUserInputQuestion {
                            id: "mode".to_string(),
                            header: "Mode".to_string(),
                            question: "Pick execution mode".to_string(),
                            is_other: false,
                            is_secret: false,
                            options: Some(vec![]),
                        }],
                    })
                    .expect("server request params should serialize"),
                ),
                trace: None,
            }),
        )
        .await;

        let JSONRPCMessage::Response(response) = read_websocket_message(websocket).await else {
            panic!("expected server request response");
        };
        assert_eq!(
            response.id,
            RequestId::String("shared-server-request".to_string())
        );
        assert_eq!(
            response.result,
            serde_json::json!({
                "answers": {
                    "mode": {
                        "answers": [expected_answer],
                    },
                },
            })
        );

        write_websocket_message(
            websocket,
            JSONRPCMessage::Request(codex_app_server_protocol::JSONRPCRequest {
                id: RequestId::String("shared-command-request".to_string()),
                method: "item/commandExecution/requestApproval".to_string(),
                params: Some(serde_json::json!({
                    "threadId": thread_id,
                    "turnId": "turn-remote-workflow",
                    "itemId": "cmd-remote-workflow",
                    "command": "pwd",
                })),
                trace: None,
            }),
        )
        .await;
        let JSONRPCMessage::Response(command_response) = read_websocket_message(websocket).await
        else {
            panic!("expected command approval response");
        };
        assert_eq!(
            command_response.id,
            RequestId::String("shared-command-request".to_string())
        );
        assert_eq!(
            command_response.result,
            serde_json::json!({
                "decision": "accept",
            })
        );

        write_websocket_message(
            websocket,
            JSONRPCMessage::Request(codex_app_server_protocol::JSONRPCRequest {
                id: RequestId::String("shared-file-request".to_string()),
                method: "item/fileChange/requestApproval".to_string(),
                params: Some(serde_json::json!({
                    "threadId": thread_id,
                    "turnId": "turn-remote-workflow",
                    "itemId": "file-remote-workflow",
                    "reason": "Need to write changes",
                })),
                trace: None,
            }),
        )
        .await;
        let JSONRPCMessage::Response(file_response) = read_websocket_message(websocket).await
        else {
            panic!("expected file approval response");
        };
        assert_eq!(
            file_response.id,
            RequestId::String("shared-file-request".to_string())
        );
        assert_eq!(
            file_response.result,
            serde_json::json!({
                "decision": "accept",
            })
        );

        write_websocket_message(
            websocket,
            JSONRPCMessage::Request(codex_app_server_protocol::JSONRPCRequest {
                id: RequestId::String("shared-mcp-request".to_string()),
                method: "mcpServer/elicitation/request".to_string(),
                params: Some(serde_json::json!({
                    "threadId": thread_id,
                    "turnId": "turn-remote-workflow",
                    "serverName": "mock-mcp",
                    "mode": "form",
                    "_meta": null,
                    "message": "Allow mock action?",
                    "requestedSchema": {
                        "type": "object",
                        "properties": {
                            "confirmed": {
                                "type": "boolean",
                            },
                        },
                        "required": ["confirmed"],
                    },
                })),
                trace: None,
            }),
        )
        .await;
        let JSONRPCMessage::Response(mcp_response) = read_websocket_message(websocket).await else {
            panic!("expected mcp elicitation response");
        };
        assert_eq!(
            mcp_response.id,
            RequestId::String("shared-mcp-request".to_string())
        );
        assert_eq!(
            mcp_response.result,
            serde_json::json!({
                "action": "accept",
                "content": {
                    "confirmed": true,
                },
                "_meta": null,
            })
        );

        write_websocket_message(
            websocket,
            JSONRPCMessage::Notification(codex_app_server_protocol::JSONRPCNotification {
                method: "item/started".to_string(),
                params: Some(
                    serde_json::to_value(ItemStartedNotification {
                        thread_id: thread_id.to_string(),
                        turn_id: "turn-remote-workflow".to_string(),
                        item: ThreadItem::DynamicToolCall {
                            id: "tool-call-remote-workflow".to_string(),
                            tool: "image-edit".to_string(),
                            arguments: serde_json::json!({
                                "prompt": format!("Sharpen image for {thread_id}"),
                                "strength": 0.5,
                            }),
                            status: DynamicToolCallStatus::InProgress,
                            content_items: None,
                            success: None,
                            duration_ms: None,
                        },
                    })
                    .expect("dynamic tool item/started should serialize"),
                ),
            }),
        )
        .await;

        write_websocket_message(
            websocket,
            JSONRPCMessage::Request(codex_app_server_protocol::JSONRPCRequest {
                id: RequestId::String("shared-dynamic-tool-call-request".to_string()),
                method: "item/tool/call".to_string(),
                params: Some(serde_json::json!({
                    "threadId": thread_id,
                    "turnId": "turn-remote-workflow",
                    "callId": "tool-call-remote-workflow",
                    "tool": "image-edit",
                    "arguments": {
                        "prompt": format!("Sharpen image for {thread_id}"),
                        "strength": 0.5,
                    },
                })),
                trace: None,
            }),
        )
        .await;
        let JSONRPCMessage::Response(dynamic_tool_response) =
            read_websocket_message(websocket).await
        else {
            panic!("expected dynamic tool call response");
        };
        assert_eq!(
            dynamic_tool_response.id,
            RequestId::String("shared-dynamic-tool-call-request".to_string())
        );
        assert_eq!(
            dynamic_tool_response.result,
            serde_json::json!({
                "contentItems": [{
                    "type": "inputText",
                    "text": format!("tool output for {thread_id}"),
                }],
                "success": true,
            })
        );

        write_websocket_message(
            websocket,
            JSONRPCMessage::Notification(codex_app_server_protocol::JSONRPCNotification {
                method: "serverRequest/resolved".to_string(),
                params: Some(
                    serde_json::to_value(ServerRequestResolvedNotification {
                        thread_id: thread_id.to_string(),
                        request_id: RequestId::String(
                            "shared-dynamic-tool-call-request".to_string(),
                        ),
                    })
                    .expect("dynamic tool serverRequest/resolved should serialize"),
                ),
            }),
        )
        .await;

        write_websocket_message(
            websocket,
            JSONRPCMessage::Notification(codex_app_server_protocol::JSONRPCNotification {
                method: "item/completed".to_string(),
                params: Some(
                    serde_json::to_value(ItemCompletedNotification {
                        thread_id: thread_id.to_string(),
                        turn_id: "turn-remote-workflow".to_string(),
                        item: ThreadItem::DynamicToolCall {
                            id: "tool-call-remote-workflow".to_string(),
                            tool: "image-edit".to_string(),
                            arguments: serde_json::json!({
                                "prompt": format!("Sharpen image for {thread_id}"),
                                "strength": 0.5,
                            }),
                            status: DynamicToolCallStatus::Completed,
                            content_items: Some(vec![
                                DynamicToolCallOutputContentItem::InputText {
                                    text: format!("tool output for {thread_id}"),
                                },
                            ]),
                            success: Some(true),
                            duration_ms: Some(7),
                        },
                    })
                    .expect("dynamic tool item/completed should serialize"),
                ),
            }),
        )
        .await;

        write_websocket_message(
            websocket,
            JSONRPCMessage::Request(codex_app_server_protocol::JSONRPCRequest {
                id: RequestId::String("shared-permissions-request".to_string()),
                method: "item/permissions/requestApproval".to_string(),
                params: Some(serde_json::json!({
                    "threadId": thread_id,
                    "turnId": "turn-remote-workflow",
                    "itemId": "perm-remote-workflow",
                    "reason": "Need wider permissions",
                    "permissions": {
                        "fileSystem": null,
                        "network": {
                            "enabled": true,
                        },
                    },
                })),
                trace: None,
            }),
        )
        .await;
        let JSONRPCMessage::Response(permissions_response) =
            read_websocket_message(websocket).await
        else {
            panic!("expected permissions approval response");
        };
        assert_eq!(
            permissions_response.id,
            RequestId::String("shared-permissions-request".to_string())
        );
        assert_eq!(
            permissions_response.result,
            serde_json::json!({
                "permissions": {
                    "network": {
                        "enabled": true,
                    },
                },
                "scope": "turn",
            })
        );

        write_websocket_message(
            websocket,
            JSONRPCMessage::Request(codex_app_server_protocol::JSONRPCRequest {
                id: RequestId::String("shared-chatgpt-refresh-request".to_string()),
                method: "account/chatgptAuthTokens/refresh".to_string(),
                params: Some(serde_json::json!({
                    "reason": "unauthorized",
                    "previousAccountId": previous_account_id,
                })),
                trace: None,
            }),
        )
        .await;
        let JSONRPCMessage::Response(refresh_response) = read_websocket_message(websocket).await
        else {
            panic!("expected chatgpt refresh response");
        };
        assert_eq!(
            refresh_response.id,
            RequestId::String("shared-chatgpt-refresh-request".to_string())
        );
        assert_eq!(
            refresh_response.result,
            serde_json::json!({
                "accessToken": format!("access-token-{previous_account_id}"),
                "chatgptAccountId": previous_account_id,
                "chatgptPlanType": "pro",
            })
        );

        while let Some(frame) = websocket.next().await {
            match frame.expect("follow-up frame should decode") {
                Message::Close(_) => break,
                Message::Ping(payload) => {
                    websocket
                        .send(Message::Pong(payload))
                        .await
                        .expect("pong should send");
                }
                Message::Text(_) | Message::Binary(_) | Message::Pong(_) | Message::Frame(_) => {}
            }
        }
    }

    async fn start_mock_remote_multi_connection_server_request_server(
        thread_id: &'static str,
        preview: &'static str,
        expected_answer: &'static str,
        previous_account_id: &'static str,
    ) -> String {
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("listener should bind");
        let addr = listener.local_addr().expect("listener address");
        tokio::spawn(async move {
            loop {
                let (stream, _) = listener.accept().await.expect("accept should succeed");
                tokio::spawn(async move {
                    let mut websocket = tokio_tungstenite::accept_async(stream)
                        .await
                        .expect("websocket upgrade should succeed");
                    expect_remote_initialize(&mut websocket).await;
                    drive_mock_remote_multi_connection_server_request_session(
                        &mut websocket,
                        thread_id,
                        preview,
                        expected_answer,
                        previous_account_id,
                    )
                    .await;
                });
            }
        });
        format!("ws://{addr}")
    }

