    async fn expect_remote_initialize<S>(websocket: &mut tokio_tungstenite::WebSocketStream<S>)
    where
        S: AsyncRead + AsyncWrite + Unpin,
    {
        let JSONRPCMessage::Request(request) = read_websocket_message(websocket).await else {
            panic!("expected initialize request");
        };
        assert_eq!(request.method, "initialize");
        write_websocket_message(
            websocket,
            JSONRPCMessage::Response(JSONRPCResponse {
                id: request.id,
                result: serde_json::json!({}),
            }),
        )
        .await;

        let JSONRPCMessage::Notification(notification) = read_websocket_message(websocket).await
        else {
            panic!("expected initialized notification");
        };
        assert_eq!(notification.method, "initialized");
    }

    async fn start_mock_exec_server() -> String {
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("listener should bind");
        let addr = listener.local_addr().expect("listener addr");
        tokio::spawn(async move {
            let (stream, _) = listener.accept().await.expect("connection should accept");
            let mut websocket = tokio_tungstenite::accept_async(stream)
                .await
                .expect("websocket should accept");

            let JSONRPCMessage::Request(request) = read_websocket_message(&mut websocket).await
            else {
                panic!("expected initialize request");
            };
            assert_eq!(request.method, "initialize");
            write_websocket_message(
                &mut websocket,
                JSONRPCMessage::Response(JSONRPCResponse {
                    id: request.id,
                    result: serde_json::json!({
                        "sessionId": "exec-session-1"
                    }),
                }),
            )
            .await;

            let JSONRPCMessage::Notification(notification) =
                read_websocket_message(&mut websocket).await
            else {
                panic!("expected initialized notification");
            };
            assert_eq!(notification.method, "initialized");
        });
        format!("ws://{addr}")
    }

    async fn read_websocket_message<S>(
        websocket: &mut tokio_tungstenite::WebSocketStream<S>,
    ) -> JSONRPCMessage
    where
        S: AsyncRead + AsyncWrite + Unpin,
    {
        loop {
            let frame = websocket
                .next()
                .await
                .expect("frame should be available")
                .expect("frame should decode");
            match frame {
                Message::Text(text) => {
                    return serde_json::from_str::<JSONRPCMessage>(&text)
                        .expect("text frame should be valid JSON-RPC");
                }
                Message::Binary(_) | Message::Ping(_) | Message::Pong(_) | Message::Frame(_) => {
                    continue;
                }
                Message::Close(_) => panic!("unexpected close frame"),
            }
        }
    }

    async fn read_websocket_request<S>(
        websocket: &mut tokio_tungstenite::WebSocketStream<S>,
    ) -> codex_app_server_protocol::JSONRPCRequest
    where
        S: AsyncRead + AsyncWrite + Unpin,
    {
        loop {
            match read_websocket_message(websocket).await {
                JSONRPCMessage::Request(request) => return request,
                JSONRPCMessage::Notification(notification)
                    if notification.method == "initialized" =>
                {
                    continue;
                }
                other => panic!("expected request, got {other:?}"),
            }
        }
    }

    async fn write_websocket_message<S>(
        websocket: &mut tokio_tungstenite::WebSocketStream<S>,
        message: JSONRPCMessage,
    ) where
        S: AsyncRead + AsyncWrite + Unpin,
    {
        websocket
            .send(Message::Text(
                serde_json::to_string(&message)
                    .expect("message should serialize")
                    .into(),
            ))
            .await
            .expect("message should send");
    }

    struct MockResponsesServer {
        uri: String,
        requests: Arc<Mutex<Vec<MockResponsesRequest>>>,
        shutdown: Option<oneshot::Sender<()>>,
        task: tokio::task::JoinHandle<()>,
    }

    #[derive(Clone)]
    struct MockResponsesRequest {
        headers: HeaderMap,
    }

    struct MockResponsesHttpResponse {
        status: StatusCode,
        content_type: &'static str,
        body: String,
    }

    impl MockResponsesServer {
        async fn wait_for_request(&self, index: usize) -> MockResponsesRequest {
            loop {
                if let Some(request) = self.requests.lock().await.get(index).cloned() {
                    return request;
                }
                sleep(Duration::from_millis(10)).await;
            }
        }

        async fn shutdown(mut self) {
            if let Some(shutdown) = self.shutdown.take() {
                let _ = shutdown.send(());
            }
            let _ = self.task.await;
        }
    }

    impl MockResponsesRequest {
        fn header(&self, name: &str) -> Option<String> {
            self.headers
                .get(name)
                .and_then(|value| value.to_str().ok())
                .map(str::to_string)
        }
    }

    async fn start_mock_responses_server_repeating_assistant(message: &str) -> MockResponsesServer {
        let body = mock_responses_sse_body(message);
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("listener should bind");
        let addr = listener.local_addr().expect("listener addr");
        let requests = Arc::new(Mutex::new(Vec::new()));
        let (shutdown_tx, shutdown_rx) = oneshot::channel::<()>();
        let recorded_requests = requests.clone();
        let task = tokio::spawn(async move {
            let app = axum::Router::new().route(
                "/v1/responses",
                axum::routing::post(move |headers: HeaderMap| {
                    let body = body.clone();
                    let requests = recorded_requests.clone();
                    async move {
                        requests.lock().await.push(MockResponsesRequest { headers });
                        (
                            [
                                (axum::http::header::CONTENT_TYPE, "text/event-stream"),
                                (axum::http::header::CACHE_CONTROL, "no-cache"),
                            ],
                            body,
                        )
                    }
                }),
            );
            let _ = axum::serve(listener, app)
                .with_graceful_shutdown(async move {
                    let _ = shutdown_rx.await;
                })
                .await;
        });

        MockResponsesServer {
            uri: format!("http://{addr}"),
            requests,
            shutdown: Some(shutdown_tx),
            task,
        }
    }

    async fn start_mock_responses_server_sequence(bodies: Vec<String>) -> MockResponsesServer {
        let responses = bodies
            .into_iter()
            .map(|body| MockResponsesHttpResponse {
                status: StatusCode::OK,
                content_type: "text/event-stream",
                body,
            })
            .collect();
        start_mock_responses_server_http_sequence(responses).await
    }

    async fn start_mock_responses_server_http_sequence(
        responses: Vec<MockResponsesHttpResponse>,
    ) -> MockResponsesServer {
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("listener should bind");
        let addr = listener.local_addr().expect("listener addr");
        let responses = Arc::new(Mutex::new(VecDeque::from(responses)));
        let requests = Arc::new(Mutex::new(Vec::new()));
        let (shutdown_tx, shutdown_rx) = oneshot::channel::<()>();
        let recorded_requests = requests.clone();
        let task = tokio::spawn(async move {
            let app = axum::Router::new().route(
                "/v1/responses",
                axum::routing::post(move |headers: HeaderMap| {
                    let responses = responses.clone();
                    let requests = recorded_requests.clone();
                    async move {
                        requests.lock().await.push(MockResponsesRequest { headers });
                        let response = responses
                            .lock()
                            .await
                            .pop_front()
                            .expect("mock responses sequence should have another response");
                        (
                            response.status,
                            [
                                (axum::http::header::CONTENT_TYPE, response.content_type),
                                (axum::http::header::CACHE_CONTROL, "no-cache"),
                            ],
                            response.body,
                        )
                    }
                }),
            );
            let _ = axum::serve(listener, app)
                .with_graceful_shutdown(async move {
                    let _ = shutdown_rx.await;
                })
                .await;
        });

        MockResponsesServer {
            uri: format!("http://{addr}"),
            requests,
            shutdown: Some(shutdown_tx),
            task,
        }
    }

